import csv
from pathlib import Path

def leer_mediciones(ruta: Path) -> tuple[list[dict], list[str]]:
    registros: list[dict] = []
    errores: list[str] = []
    with ruta.open(encoding='utf-8', newline='') as archivo:
        lector = csv.DictReader(archivo)
        requeridas = {'paciente', 'tiempo_s', 'frecuencia_lpm'}
        if not requeridas.issubset(lector.fieldnames or []):
            raise ValueError('Faltan columnas obligatorias')
        for numero, fila in enumerate(lector, start=2):
            try:
                paciente = fila['paciente'].strip()
                tiempo = float(fila['tiempo_s'])
                frecuencia = float(fila['frecuencia_lpm'])
                if not paciente or tiempo < 0 or not 20 <= frecuencia <= 250:
                    raise ValueError('Valores fuera del dominio educativo')
                registros.append({'paciente': paciente, 'tiempo_s': tiempo, 'frecuencia_lpm': frecuencia})
            except (TypeError, ValueError) as error:
                errores.append(f'Fila {numero}: {error}')
    return registros, errores
